import{_ as t,o,c as n,a6 as i,iN as e,iO as p,iP as l,iQ as g,iR as h,iS as d,iT as c,iU as m,iV as _,iW as b,iX as u,iY as f,iZ as P,i_ as x,i$ as k,j0 as j,j1 as K,j2 as S,j3 as T,j4 as r,j5 as $,j6 as D,j7 as V,j8 as v,g8 as w,g9 as y,ga as s,j9 as A,ja as I,jb as Q}from"./chunks/framework.UYVGz2W_.js";const J=JSON.parse('{"title":"制作レポートの作成","description":"","frontmatter":{},"headers":[],"relativePath":"ja/production-report/index.md","filePath":"ja/production-report/index.md"}'),W={name:"ja/production-report/index.md"};function C(N,a,F,B,E,O){return o(),n("div",null,[...a[0]||(a[0]=[i('<h1 id="制作レポートの作成" tabindex="-1">制作レポートの作成 <a class="header-anchor" href="#制作レポートの作成" aria-label="Permalink to “制作レポートの作成”">​</a></h1><h2 id="制作の概要" tabindex="-1">制作の概要 <a class="header-anchor" href="#制作の概要" aria-label="Permalink to “制作の概要”">​</a></h2><p>プロデューサーとして、制作プロセス全体を包括的に把握することは不可欠です。</p><p>Kitsuは、通知に圧倒されたり、集中力を欠いたりすることなく、情報を把握し、制作を効率的に管理するためのさまざまなツールを提供します。</p><h3 id="ニュースフィードの機能" tabindex="-1">ニュースフィードの機能 <a class="header-anchor" href="#ニュースフィードの機能" aria-label="Permalink to “ニュースフィードの機能”">​</a></h3><p>ニュースフィードセクションでは、制作に関するリアルタイムの更新情報が表示されます。</p><ul><li><strong>リアルタイム更新</strong>：ステータスの変更がすべて、分単位でリアルタイムに表示されます。</li><li><strong>サマリー表示</strong>：画面の右側に、ニュースアイテムの総数とステータスごとの内訳が表示されます。</li><li><strong>フィルタリングオプション</strong>：タスクのステータス、タスクの種類、担当者別にリストをフィルタリングして、特定のエリアに焦点を絞ることができます。</li><li><strong>コメントパネル</strong>：行をクリックすると、右側にコメントパネルが開き、必要な詳細情報が表示されます。</li></ul><p><img src="'+e+'" alt="ニュースフィードページ"></p><h4 id="フィルタの使用" tabindex="-1">フィルタの使用 <a class="header-anchor" href="#フィルタの使用" aria-label="Permalink to “フィルタの使用”">​</a></h4><p><strong>フィルタビルダー</strong>ボタンを使用して、情報を表示する期間をカスタマイズできます。これは、特定のスーパーバイザーや期間に焦点を当てる場合に便利です。</p><p><img src="'+p+'" alt="ニュースフィードページの詳細"></p><h4 id="例" tabindex="-1">例 <a class="header-anchor" href="#例" aria-label="Permalink to “例”">​</a></h4><p>特定の月のスーパーバイザーに焦点を当てたい場合は、名前を選択し、<strong>[From]</strong>ボックスで日付を選択します。</p><p><img src="'+l+'" alt="ニュースフィードページのコメント"></p><h2 id="制作の現状を把握する" tabindex="-1">制作の現状を把握する <a class="header-anchor" href="#制作の現状を把握する" aria-label="Permalink to “制作の現状を把握する”">​</a></h2><p>制作の現状を把握することは非常に重要です。Kitsuは詳細な統計と視覚化を提供し、進捗状況を効果的に追跡できるようにします。</p><h3 id="ショートフィルム-長編映画固有の機能" tabindex="-1">ショートフィルム/長編映画固有の機能 <a class="header-anchor" href="#ショートフィルム-長編映画固有の機能" aria-label="Permalink to “ショートフィルム/長編映画固有の機能”">​</a></h3><p>ここでは、ショートフィルム/長編映画のワークフローに固有の機能について説明します。</p><h4 id="シーケンス統計" tabindex="-1">シーケンス統計 <a class="header-anchor" href="#シーケンス統計" aria-label="Permalink to “シーケンス統計”">​</a></h4><p><strong>シーケンス統計</strong>ページでは、制作の状況をシーケンスごとに円グラフで表示します。 円グラフの色分けはステータスに対応しており、制作の状況を素早く把握できます。</p><p><img src="'+g+'" alt="グローバルビューシーケンス"></p><ul><li><strong>すべてのシーケンス</strong>：最初の行は制作全体を表します。</li><li><strong>すべてのタスク</strong>：最初の列にはすべてのタスクが同時に表示されます。</li></ul><p>最初の円グラフに注目すると、制作の正確な状態を確認できます。さらに詳細を確認するには、残りの行を見て、各タスクタイプの状態をグローバルに把握します。</p><h4 id="アセットタイプ統計" tabindex="-1">アセットタイプ統計 <a class="header-anchor" href="#アセットタイプ統計" aria-label="Permalink to “アセットタイプ統計”">​</a></h4><p>シーケンス統計と同様に、<strong>アセットタイプ統計</strong>ページではアセットタイプごとの円グラフが表示され、制作全体におけるアセットのステータスを明確に把握できます。</p><p><img src="'+h+'" alt="グローバルビューアセット"></p><h4 id="カウントビュー" tabindex="-1">カウントビュー <a class="header-anchor" href="#カウントビュー" aria-label="Permalink to “カウントビュー”">​</a></h4><p>また、<strong>カウント</strong>としてデータを表示し、アセット、ショット、フレームの正確な数と、それらのステータスごとの割合を確認することもできます。</p><p><img src="'+d+'" alt="グローバルビューシーケンスカウント"></p><h4 id="データのエクスポート" tabindex="-1">データのエクスポート <a class="header-anchor" href="#データのエクスポート" aria-label="Permalink to “データのエクスポート”">​</a></h4><p>このページは <code>.csv</code> テキストファイルとしてエクスポートし、スプレッドシートソフトウェアにインポートして、さらに分析やレポート作成を行うことができます。</p><p>これらのツールを活用することで、制作プロセスを常に把握し、すべてがスケジュール通りに円滑に進行していることを確認できます。</p><h3 id="テレビ番組固有" tabindex="-1">テレビ番組固有 <a class="header-anchor" href="#テレビ番組固有" aria-label="Permalink to “テレビ番組固有”">​</a></h3><p><strong>エピソード統計ページ</strong>では、テレビ番組に関する追加情報にアクセスできます。</p><h3 id="リテイクの表示" tabindex="-1">リテイクの表示 <a class="header-anchor" href="#リテイクの表示" aria-label="Permalink to “リテイクの表示”">​</a></h3><p><strong>エピソード統計</strong>ページのデフォルト設定は<strong>リテイク</strong>です。この表示では、各タスクタイプにおける各エピソードのリテイク（やり直し）の回数を参照できます。表示される色は3色のみです。</p><ul><li><strong>検証済みの場合は緑</strong></li><li><strong>リテイクの場合は赤</strong></li><li><strong>進行中の場合はグレー</strong></li></ul><p><img src="'+c+'" alt="グローバルビューのエピソード"></p><p>エピソードを展開すると、各テイクの割合とリテイクと承認の推移が表示されます。これにより、各タスクごとのエピソードの進捗状況を確認できます。</p><p><img src="'+m+'" alt="グローバルビューのエピソード展開"></p><p>通常、最初のエピソードには多くのやり取りがありますが、時間が経つにつれて改善されていくはずです。しかし、後半のエピソードにまだ多くのリテイクがある場合は、何か修正すべき点があるはずです。ディレクターやスーパーバイザーと問題について話し合う時が来たということです。</p><h3 id="ステータス表示" tabindex="-1">ステータス表示 <a class="header-anchor" href="#ステータス表示" aria-label="Permalink to “ステータス表示”">​</a></h3><p>データ表示の2つ目のオプションは、<strong>ステータス</strong>です。このステータス表示は、<strong>シーケンス</strong> / <strong>アセットタイプ</strong> 統計ページと同様に機能します。</p><p><img src="'+_+'" alt="グローバルビュー エピソードステータス"></p><p>データを<strong>カウント</strong>として表示することもできます。この方法では、ステータスごとのショット/フレームの正確な数とパーセンテージが表示されます。</p><p><img src="'+b+'" alt="グローバルビュー エピソードステータスカウント"></p><p>このページを <code>.csv</code> テキストファイルとしてエクスポートし、スプレッドシートソフトウェアにインポートすることができます。</p><h2 id="タスクが期限内に完了していることを確認する" tabindex="-1">タスクが期限内に完了していることを確認する <a class="header-anchor" href="#タスクが期限内に完了していることを確認する" aria-label="Permalink to “タスクが期限内に完了していることを確認する”">​</a></h2><p>タスクが期限内に完了しているかどうかを確認するには、次の2つの情報が必要です。</p><ul><li>タスクの <strong>タスクタイプ</strong></li><li>タスクの <strong>見積もり</strong>（入札）の日数、およびタスクの <strong>開始予定日</strong>と<strong>期限</strong>。</li></ul><p>この情報を入力すると、タスクタイプのページで<strong>見積りと実績</strong>を比較することができます。</p><p><img src="'+u+'" alt="タスクタイプ入力済み"></p><h3 id="見積りと実績を比較する方法" tabindex="-1">見積りと実績を比較する方法 <a class="header-anchor" href="#見積りと実績を比較する方法" aria-label="Permalink to “見積りと実績を比較する方法”">​</a></h3><p>これを行うには主に2つの方法があります。</p><ol><li><strong>期限ステータスによるフィルタリング</strong></li><li><strong>ガントチャートを使用する</strong></li></ol><p>::: ヒント Kitsu は、<strong>WIP</strong>（作業中）と <strong>WFA</strong>（承認待ち）の日付とステータスを自動的に取得します。 <strong>見積開始日</strong>と<strong>アーティストが実際に開始した日</strong>を比較したり、<strong>見積期限日</strong>と<strong>アーティストが承認を求めた日</strong>を比較することができます。 :::</p><h3 id="期限日ステータスによるフィルタリング" tabindex="-1">期限日ステータスによるフィルタリング <a class="header-anchor" href="#期限日ステータスによるフィルタリング" aria-label="Permalink to “期限日ステータスによるフィルタリング”">​</a></h3><p><strong>タスク</strong>] タブで、最初に表示されるフィルタは [<strong>期日ステータス</strong>] です。 [<strong>期日ステータス</strong>] を [<strong>今日より前に期日が到来</strong>] に設定すると、[<strong>期日が今日より前に設定</strong>] されたすべてのタスクが表示されます。</p><p>次に、完了したものとまだ完了していないものを判断します。 [<strong>-完了</strong>] フィルタを使用すると、完了したタスクが除外されます。</p><p><img src="'+f+'" alt="タスクタイプ 期限は今日まで"></p><p>これは、2つのフィルタが適用されたすべての期限遅れのタスクを表示します。つまり、<strong>見積もり期限</strong>後にのみ確認されるということです。ページ下部のサマリーは、適用されたフィルタに基づいてリアルタイムで更新されます。</p><p>このページを <code>CSV</code> ファイルとしてエクスポートし、スプレッドシートソフトウェアで開くことができます。</p><h3 id="遅延ステータスフィルタの使用" tabindex="-1">遅延ステータスフィルタの使用 <a class="header-anchor" href="#遅延ステータスフィルタの使用" aria-label="Permalink to “遅延ステータスフィルタの使用”">​</a></h3><p>ページに組み込まれている<strong>「遅延ステータス」</strong>フィルタを使用すると、見積もりよりも時間がかかったタスク（<strong>「見積もり超過時間」</strong>）をすぐに確認することができます。</p><p><img src="'+P+'" alt="タスクタイプの見積もり超過時間"></p><p><strong>期限遅延</strong>オプションを使用して、遅延したタスクをフィルタリングします。タスクが遅延しているかどうかを計算するには、次の2つの方法があります。</p><ol><li><strong>見積もり期限</strong>と<strong>フィードバック</strong>の比較</li><li><strong>見積もり期限</strong>と<strong>完了</strong>の比較</li></ol><p>スタジオの計算方法に応じて、Kitsuが回答を提供します。</p><p><img src="'+x+'" alt="タスクタイプ 遅延フィードバック"></p><h3 id="ガントチャートを使用する" tabindex="-1">ガントチャートを使用する <a class="header-anchor" href="#ガントチャートを使用する" aria-label="Permalink to “ガントチャートを使用する”">​</a></h3><p><strong>タスクタイプページ</strong>で、<strong>スケジュール</strong>タブに移動します。 制作スケジュールで設定されたこのタスクタイプの<strong>開始</strong>日と<strong>終了</strong>日は、画面の上部に表示されます。</p><p><strong>ガントチャート</strong>は、これらの日付の前後が濃いグレーで表示され、タスクのタイミングを視覚的に示します。</p><p><img src="'+k+'" alt="タスクタイプスケジュール"></p><p><strong>着色</strong>を<strong>ステータスカラー</strong>から<strong>遅延は赤</strong>に変更します。これにより、期限通りのタスクは<strong>グレー</strong>で、遅延しているタスクは<strong>赤</strong>で表示されます。</p><p><img src="'+j+'" alt="タスクタイプスケジュール遅延"></p><p>詳細を確認するには、<strong>[タスク]</strong> タブに戻ることができます。また、Kitsuはタブ間でフィルタを保持します。</p><h2 id="タスクが遅延している理由を理解する" tabindex="-1">タスクが遅延している理由を理解する <a class="header-anchor" href="#タスクが遅延している理由を理解する" aria-label="Permalink to “タスクが遅延している理由を理解する”">​</a></h2><p>どのタスクが遅延しているか、または遅延する予定かを知ったので、<strong>その理由</strong>を理解する必要があります。タスクが遅延する理由はいくつかあります。</p><ul><li>アーティストが多くのタスクに圧倒されている。</li><li>タスクのやり取りが多すぎる。</li><li>タスクが過小評価されている可能性があり、期限内に完了させるのが難しい。</li><li>前のタスクがすでに遅れている。</li></ul><h3 id="アーティストの作業負荷の確認" tabindex="-1">アーティストの作業負荷の確認 <a class="header-anchor" href="#アーティストの作業負荷の確認" aria-label="Permalink to “アーティストの作業負荷の確認”">​</a></h3><p>アーティストのタスク数を確認するには、[タスク] タブでアーティスト名を指定して [タスクタイプ] ページをフィルタリングします。</p><p><img src="'+K+'" alt="タスクタイプアーティスト"></p><p>また、<strong>-done</strong> フィルターを追加して、そのアーティストが完了したタスクを確認することもできます。次に、<strong>Due Date Status</strong> フィルターを <strong>Due previous week</strong> または <strong>Due this week</strong> に設定して、必要な情報を検索します。</p><p><img src="'+S+'" alt="Task Type Artist Filtered"></p><p>これにより、そのアーティストが完了すべきタスクの数が表示されます。</p><h3 id="やりとりの確認" tabindex="-1">やりとりの確認 <a class="header-anchor" href="#やりとりの確認" aria-label="Permalink to “やりとりの確認”">​</a></h3><p>やりとりの回数を特定するには、[タスク] タブの [リテイク] 列を確認します。 <strong>赤いドット</strong>はそれぞれ <strong>リテイク</strong> を表します。 該当行をクリックすると、<strong>コメントパネル</strong> が開き、タスクの全履歴を確認できます。 これは、アーティストが指示を誤解していたかどうか、指示が各バージョンで変更されたかどうかなど、何が起こっているかを把握する最善の方法です。</p><p><img src="'+T+'" alt="タスクタイプのリテイク"></p><h3 id="タスクが過小評価されていないかを確認する" tabindex="-1">タスクが過小評価されていないかを確認する <a class="header-anchor" href="#タスクが過小評価されていないかを確認する" aria-label="Permalink to “タスクが過小評価されていないかを確認する”">​</a></h3><p>タスクが過小評価されていないかを確認するには、グローバルページに戻り、ショットまたはアセットの名前をクリックして、キャスティングやその他の追加情報を確認します。 たとえば、シーンに登場するキャラクターが多すぎる場合や、アクションシーンが大掛かりである場合などです。</p><p><img src="'+r+'" alt="ショットの詳細 キャスティング"></p><h3 id="前作業の確認" tabindex="-1">前作業の確認 <a class="header-anchor" href="#前作業の確認" aria-label="Permalink to “前作業の確認”">​</a></h3><p>最後に、アセット/ショットの詳細を表示しながら、前作業を確認することができます。クリックすると、<strong>タスクタイプ</strong>専用のページに移動し、以前の作業に関する詳細情報を確認できます。これにより、以前のタスクの遅延が現在のタスクに影響しているかどうかを把握できます。</p><h2 id="見積もり以上の期間" tabindex="-1">見積もり以上の期間 <a class="header-anchor" href="#見積もり以上の期間" aria-label="Permalink to “見積もり以上の期間”">​</a></h2><p>全体像に焦点を当て、<strong>入札</strong>の全体的な概要を把握するには、さまざまなページで、見積もりの<strong>人日</strong>と実際の<strong>作業日数</strong>を比較できます。</p><h3 id="見積もりサマリー" tabindex="-1">見積もりサマリー <a class="header-anchor" href="#見積もりサマリー" aria-label="Permalink to “見積もりサマリー”">​</a></h3><p>ショットのグローバルページでは、すべての見積もりの期間のサマリーを確認できます。また、より詳細な情報を得るためにフィルターを適用することもできます。</p><p>例えば、特定のシーケンスに焦点を当てるには、シーケンス名でグローバルページをフィルタリングします。すると、下部のサマリーが更新されます。</p><p><img src="'+$+'" alt="グローバルショットページのサマリー（フィルタリング）"></p><p>これにより、特定のシーケンスの<strong>期間</strong>と<strong>見積もり</strong>を知ることができます。</p><p>同様に、グローバルアセットページをフィルタリングすることもできます。</p><p>たとえば、<strong>キャラクター</strong>などの特定の<strong>アセットタイプ</strong>でフィルタリングすることができます。下部のサマリーが更新され、そのアセットタイプの推定時間と期間が表示されます。</p><p>![グローバルアセットページのサマリーフィルター] (../img/getting-started/global_asset_sumup.png)</p><p>タスクタイプ別 見積もり期間</p><p>詳細を確認するには、タスクタイプの名前をクリックします。画面下部のサマリーには、この特定のタスクタイプに対する<strong>期間</strong>と<strong>見積もり</strong>が表示されます。</p><p><img src="'+D+'" alt="タスクタイプ別サマリー"></p><p>全体像を確認したり、<strong>特定のステータス</strong>や<strong>アーティスト名</strong>に焦点を当てることができます。グローバルページと同様に、適用したフィルタに応じてサマリーが更新されます。</p><p><img src="'+V+'" alt="タスクタイプサマリーフィルタリング"></p><p>このように、特定のタスクやアーティストのパフォーマンスや効率を詳細に監視し、見積もりが実際の所要時間と一致していることを確認し、必要に応じて調整することができます。</p><h3 id="アセット-ショットの見積もり所要時間" tabindex="-1">アセット/ショットの見積もり所要時間 <a class="header-anchor" href="#アセット-ショットの見積もり所要時間" aria-label="Permalink to “アセット/ショットの見積もり所要時間”">​</a></h3><p>詳細を精査するには、キット内の各アセットとショットに対して、<strong>「見積もり」</strong>と<strong>「所要時間」</strong>（期間）の列を表示することができます。</p><p>ショットまたはアセットのグローバルページでは、各タスクの<strong>「見積もり」</strong>と<strong>「期間」</strong>の合計を確認できます。これにより、不一致や問題を素早く特定できます。</p><p><img src="'+v+'" alt="グローバルショット見積もり"></p><h3 id="詳細分析" tabindex="-1">詳細分析 <a class="header-anchor" href="#詳細分析" aria-label="Permalink to “詳細分析”">​</a></h3><p>何かがおかしいと思われたり、さらに調査が必要な場合は、アセット名またはショット名をクリックして詳細ページに移動します。</p><p>詳細ページの画面左上には、アセットまたはショットのライフサイクルの概要が表示されます。これには、各タスクの<strong>ステータス</strong>、<strong>見積もり</strong>、<strong>期間</strong>、<strong>開始日と期限</strong>、<strong>割り当て</strong>の詳細が含まれます。</p><p><img src="'+r+'" alt="詳細ショット見積もり"></p><p>この包括的なビューは、相違点がどこにあるかを把握し、必要に応じて修正措置を取るのに役立ちます。これらの詳細を綿密に監視することで、見積もり時間と実際の所要時間の整合性をより確実にし、より正確な将来の計画とリソースの割り当てが可能になります。</p><h2 id="クォータの確認" tabindex="-1">クォータの確認 <a class="header-anchor" href="#クォータの確認" aria-label="Permalink to “クォータの確認”">​</a></h2><p>Kitsuは、<strong>ショットのタスクタイプ</strong>ごとのクォータを計算する2つの方法を提供しています。</p><h3 id="方法1-タイムシートに基づく計算" tabindex="-1">方法1：タイムシートに基づく計算 <a class="header-anchor" href="#方法1-タイムシートに基づく計算" aria-label="Permalink to “方法1：タイムシートに基づく計算”">​</a></h3><p>この方法では、タイムシートに記録されたタスクに費やされた時間に応じてクォータに重み付けをします。</p><ul><li><strong>タスクの完了</strong>：最初のフィードバックリクエスト時にショットが完了したとみなされます。その後、タイムシートに記録された時間に基づいてクォータに重み付けがされます。</li></ul><p><img src="'+w+'" alt="Quotas stat page day weighted"></p><p>この例では、Kitsuはタイムシートデータを使用して日々のノルマを計算します。</p><p><img src="'+y+'" alt="Quotas stat page day weighted detail"></p><h3 id="方法-2-ステータスに基づく計算" tabindex="-1">方法 2: ステータスに基づく計算 <a class="header-anchor" href="#方法-2-ステータスに基づく計算" aria-label="Permalink to “方法 2: ステータスに基づく計算”">​</a></h3><p>タイムシートデータが利用できない場合、Kitsuはステータスの変更を使用してノルマを計算します。</p><ul><li><strong>タスクの開始</strong>: タスクのステータスがWIPに変更された時点で、タスクが開始されたと見なされます。</li><li><strong>タスクの完了</strong>: フィードバックのリクエストが作成された日に、タスクが完了したと見なされます。</li></ul><h3 id="詳細なノルマ計算" tabindex="-1">詳細なノルマ計算 <a class="header-anchor" href="#詳細なノルマ計算" aria-label="Permalink to “詳細なノルマ計算”">​</a></h3><p>Kitsuは、タスクの開始日と終了日の間の全営業日について、完了したフレームを分割し、各アーティストに割り当てます。1日/1週間/1か月ごとに提出されたフレーム（または秒数、またはタスク）の数を割り当てます。</p><p><img src="'+s+'" alt="Quotas stat page day status"></p><p>いつでも数字をクリックすると、右パネルに詳細情報が表示されます。</p><p><img src="'+s+'" alt="Quotas stat page day weighted"></p><p>::: 危険 <strong>注意</strong>: タイムシートが記入されていない場合、Kitsuは以下の条件を考慮します。</p><ul><li>タスクがWIPにステータスが変更されたときに開始された。</li><li>タスクがフィードバックリクエストが作成された日に完了した。 :::</li></ul><p>この方法では、詳細なタイムシートデータがなくても、タスクの進捗を確実に追跡し、正確なノルマを計算することができます。</p><h2 id="チームのタイムシート" tabindex="-1">チームのタイムシート <a class="header-anchor" href="#チームのタイムシート" aria-label="Permalink to “チームのタイムシート”">​</a></h2><p>::: 警告 これまでのすべての章は、各タスクに<strong>見積もり</strong>と<strong>期間</strong>が入力されていることを前提にしています。 :::</p><p>全員が自分の役割を果たさなければなりません。あなたと上司は見積もりを担当し、チームメンバーはタイムシートを入力します。</p><p>メインメニューに移動し、タイムシートページを選択します。</p><p><img src="'+A+'" alt="タイムシート全体日"></p><h3 id="タイムシートの表示" tabindex="-1">タイムシートの表示 <a class="header-anchor" href="#タイムシートの表示" aria-label="Permalink to “タイムシートの表示”">​</a></h3><p>このページでは、各チームメンバーのタイムシートを日ごとに表示することができます。これにより、メンバーが毎日タイムシートを記入しているか、休みを取ったか、あるいは残業したかを確認することができます。</p><p>タイムシートの入力内容について疑問がある場合は、該当する行をクリックすると、制作、タスクの種類、特定のタスクの詳細を確認できます。</p><p><img src="'+I+'" alt="タイムシートの詳細（日単位）"></p><p>日単位で問題がなければ、<strong>詳細レベル</strong>を日単位から週単位、月単位、年単位に変更できます。</p><p><img src="'+Q+'" alt="タイムシート全体 週"></p><p>管理しているすべての制作を同時に表示することも、各制作を個別に表示することもできます。</p><h3 id="タイムシートのエクスポート" tabindex="-1">タイムシートのエクスポート <a class="header-anchor" href="#タイムシートのエクスポート" aria-label="Permalink to “タイムシートのエクスポート”">​</a></h3><p>Kitsuの他のすべてのページと同様に、タイムシートのデータをCSVファイルとしてエクスポートし、表計算ソフトウェアで開いてさらに分析を行うことができます。</p>',151)])])}const U=t(W,[["render",C]]);export{J as __pageData,U as default};
